err_t app_oled_play_boot_animation(void)
{
    uint8_t index;

    for (index = 0U; index < OLED_BOOT_ANIM_FRAME_COUNT; index++)
    {
        bsp_oled_iic_show_frame(s_oledBootAnim[index]);
        bsp_oled_iic_refresh();
        osDelay(OLED_BOOT_ANIM_FRAME_DELAY);
    }

    return ERR_OK;
}
